WatchFaceSJ::~WatchFaceSJ() {
  lv_task_del(taskRefresh);
  lv_obj_clean(lv_scr_act());
  bitmap.header.always_zero = 0; //Initialization
  bitmap.header.w = 240;                     // Setting the Width (or) Horizontal length of the image (number of px)
  bitmap.header.h = 240;                     // Setting the Height (or) vertical length of the image (number of px)
  bitmap.data_size = 240 * 240 * LV_COLOR_SIZE / 8; //Allocation of memory for the image
  bitmap.header.cf = LV_IMG_CF_TRUE_COLOR; // Sets the color scheme for the image
  bitmap.data = bitmap_map;                // Maps the Image data to the Array
  lv_obj_t *img_src = lv_img_create(lv_scr_act(), NULL);  // Create an image object
  lv_img_set_src(img_src, &bitmap);        // Set the created file as image (<name>) 
  lv_obj_set_pos(img_src, 0, 0);
}

